fn solve(s: String) -> String {
    let mut result = String::new();

    for c in s.chars() {
        match c {
            'a'..='z' => result.push(c),
            '*' => {
                if !result.is_empty() {
                    result.pop();
                }
            },
            '#' => {
                let mut temp = result.clone();
                result.push_str(&temp);
            },
            '%' => {
                result = result.chars().rev().collect();
            },
            _ => {}
        }
    }

    result
}
